<?php declare(strict_types=1);
namespace SkyFi\System\Repositories;
use SkyFi\System\Contracts\NotificationPreferenceRepositoryContract;
final class PdoNotificationPreferenceRepository extends PdoSystemRepository implements NotificationPreferenceRepositoryContract { private array $allowed=['email_enabled','sms_enabled','in_app_enabled','alert_preferences','reminder_preferences','email_templates_enabled','sms_provider_placeholder']; private array $json=['alert_preferences','reminder_preferences','sms_provider_placeholder']; public function first(): array { return $this->singleton('notification_preferences', self::defaults(), $this->json); } public function update(array $data, ?int $userId=null): array { return $this->updateSingleton('notification_preferences',$data,self::defaults(),$this->allowed,$this->json,$userId); } public static function defaults(): array { return ['email_enabled'=>1,'sms_enabled'=>0,'in_app_enabled'=>1,'alert_preferences'=>['network'=>true,'billing'=>true,'support'=>true],'reminder_preferences'=>['invoice_due'=>true,'ticket_follow_up'=>true],'email_templates_enabled'=>1,'sms_provider_placeholder'=>['enabled'=>false,'status'=>'placeholder']]; }}
